import { useState, useEffect } from "react";
import { Link } from "react-router-dom";
import API from "../../services/api";
import "./css/UserDashboard.css";

function SavedJobs() {
  const [jobs, setJobs] = useState([]);

  useEffect(() => {
    fetchJobs();
  }, []);

  const fetchJobs = async () => {
    try {
      const res = await API.get("/user/saved-jobs");
      setJobs(res.data);
    } catch (e) {
      console.error(e);
    }
  };

  return (
    <div className="dashboard-layout">
      <aside className="dashboard-sidebar">
        <div className="sidebar-logo">
          <div className="logo-icon">⚡</div>
          UserPortal 🚀
        </div>

        <nav className="nav-menu">
           <Link to="/user/dashboard" className="nav-link">🏠 Dashboard</Link>
          <Link to="/user/resume" className="nav-link">📄 My Resume</Link>
          <Link to="/user/alerts" className="nav-link">🔔 Job Alerts</Link>
          <Link to="/user/saved-jobs" className="nav-link active">⭐ Saved Jobs</Link>
          <Link to="/user/account" className="nav-link">⚙️ Account</Link>
        </nav>
      </aside>

      <main className="dashboard-main">
        <header className="dashboard-header-flex">
          <div className="header-titles">
            <h1>Saved Jobs ⭐</h1>
            <p>Vacancies you have bookmarked for later application.</p>
          </div>
        </header>

        <div style={{display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1.5rem'}}>
          {jobs.map((job) => (
             <div key={job.id} style={{
                background: '#ffffff',
                border: '1px solid #f1f5f9',
                borderRadius: '16px',
                padding: '2rem',
                boxShadow: '0 4px 6px -1px rgba(0,0,0,0.02)'
             }}>
                <div style={{display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: '1.5rem'}}>
                   <div>
                     <h3 style={{fontSize: '1.25rem', color: '#1e293b', marginBottom: '0.25rem'}}>{job.title}</h3>
                     <p style={{color: '#64748b', fontWeight: 500}}>{job.company}</p>
                   </div>
                   <div style={{background: '#dcfce7', color: '#16a34a', padding: '0.5rem 1rem', borderRadius: '999px', fontWeight: 800, fontSize: '0.875rem'}}>
                     {job.match}% MATCH
                   </div>
                </div>
                <button style={{width: '100%', background: '#3b82f6', color: 'white', padding: '1rem', border: 'none', borderRadius: '12px', fontWeight: 700, cursor: 'pointer', transition: '0.2s'}}>
                  Apply Now 🚀
                </button>
             </div>
          ))}
          {jobs.length === 0 && <p style={{color: '#94a3b8'}}>No saved jobs.</p>}
        </div>
      </main>
    </div>
  );
}

export default SavedJobs;
